#include <stdio.h>
#include <string.h>
#include <stdint.h>
#include "../include/params.h"
#include "../include/kpke.h"
#include "../include/util.h"

static const char dkpke_hex[] =
    "";

static const char expected_c_hex[] =
    "";

static const char expected_m_hex[] =
    "a741ec2002be6f4fa76037b7f0644f833fa823e630401a39d3240c6e82a430bb";

static const char ekpke_hex[] = 
    "";

static const char r_hex[] = 
    "16ce593e016201dee38926330bb78b1f0cab703862c66dc1f5fdf80f2da01ca7";


void hex_to_bytes(const char *hex, uint8_t *out, size_t len) {
    for(size_t i = 0; i < len; i++) {
        sscanf(hex + 2*i, "%02hhx", &out[i]);
    }
}

int main() {
    uint8_t ek[800], dk[768], c[768], expected_m[32], recovered_m[32], r[32], expected_c[768];

    hex_to_bytes(dkpke_hex, dk, 768);
    hex_to_bytes(expected_c_hex, expected_c, 768);
    hex_to_bytes(expected_m_hex, expected_m, 32);
    hex_to_bytes(ekpke_hex, ek, 800);
    hex_to_bytes(r_hex, r, 32);

    k_pke_encrypt(ek, expected_m, r, c, &ML_KEM_512);

    for(uint16_t i = 0; i < ML_KEM_512_CTEXT; i++) {
        printf("%d ", c[i]);
    }
printf("\n\n");
    for(uint16_t i = 0; i < ML_KEM_512_CTEXT; i++) {
        printf("%d ", expected_c[i]);
    }

    if(memcmp(c, expected_c, 768) == 0) {
        printf("k_pke_encrypt PASSED\n");
    } else {
        printf("k_pke_encrypt FAILED\n");
    }

    k_pke_decrypt(dk, c, recovered_m, &ML_KEM_512);

    if(memcmp(recovered_m, expected_m, 32) == 0) {
        printf("k_pke_roundtrip PASSED\n");
    } else {
        printf("k_pke roundtrip FAILED\n");
        printf("  expected:  ");
        for(int i = 0; i < 32; i++) printf("%02x", expected_m[i]);
        printf("\n  recovered: ");
        for(int i = 0; i < 32; i++) printf("%02x", recovered_m[i]);
        printf("\n");
    }

    return 0;
}